const https = require('https');
const http = require('http');
const { URL } = require('url');

function fetchUrlMetadata(targetUrl, callback) {
  try {
    const parsedUrl = new URL(targetUrl);
    const protocol = parsedUrl.protocol === 'https:' ? https : http;
    
    const options = {
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; MetadataBot/1.0)',
        'Accept': 'text/html,application/xhtml+xml',
        'Accept-Language': 'en-US,en;q=0.9'
      },
      timeout: 10000
    };

    const request = protocol.get(targetUrl, options, (response) => {
      if (response.statusCode >= 300 && response.statusCode < 400 && response.headers.location) {
        const redirectUrl = new URL(response.headers.location, targetUrl).href;
        return fetchUrlMetadata(redirectUrl, callback);
      }

      if (response.statusCode !== 200) {
        return callback(new Error(`HTTP ${response.statusCode}: ${response.statusMessage}`));
      }

      let html = '';
      
      response.on('data', (chunk) => {
        html += chunk.toString();
        if (html.length > 1048576) {
          response.destroy();
          return callback(new Error('Response too large'));
        }
      });

      response.on('end', () => {
        try {
          const metadata = parseMetadata(html);
          callback(null, metadata);
        } catch (error) {
          callback(error);
        }
      });
    });

    request.on('error', (error) => {
      callback(error);
    });

    request.on('timeout', () => {
      request.destroy();
      callback(new Error('Request timeout'));
    });

  } catch (error) {
    callback(error);
  }
}

function parseMetadata(html) {
  const metadata = {
    title: '',
    description: '',
    ogTitle: '',
    ogDescription: '',
    ogImage: '',
    ogUrl: '',
    ogType: '',
    ogSiteName: ''
  };

  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = decodeHtmlEntities(titleMatch[1].trim());
  }

  const descriptionMatch = html.match(/<meta\s+name=["']description["'][^>]*content=["']([^"']+)["']/i) ||
                          html.match(/<meta\s+content=["']([^"']+)["'][^>]*name=["']description["']/i);
  if (descriptionMatch) {
    metadata.description = decodeHtmlEntities(descriptionMatch[1].trim());
  }

  const ogTags = {
    'og:title': 'ogTitle',
    'og:description': 'ogDescription',
    'og:image': 'ogImage',
    'og:url': 'ogUrl',
    'og:type': 'ogType',
    'og:site_name': 'ogSiteName'
  };

  for (const [ogTag, key] of Object.entries(ogTags)) {
    const pattern1 = new RegExp(`<meta\\s+property=["']${ogTag}["'][^>]*content=["']([^"']+)["']`, 'i');
    const pattern2 = new RegExp(`<meta\\s+content=["']([^"']+)["'][^>]*property=["']${ogTag}["']`, 'i');
    
    const match = html.match(pattern1) || html.match(pattern2);
    if (match) {
      metadata[key] = decodeHtmlEntities(match[1].trim());
    }
  }

  return metadata;
}

function decodeHtmlEntities(text) {
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&#x27;': "'",
    '&#x2F;': '/',
    '&#47;': '/'
  };

  return text.replace(/&[#a-z0-9]+;/gi, (entity) => {
    return entities[entity.toLowerCase()] || entity;
  });
}

exports.fetchUrlMetadata = (req, res) => {
  res.set('Access-Control-Allow-Origin', '*');
  
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Methods', 'GET, POST');
    res.set('Access-Control-Allow-Headers', 'Content-Type');
    res.set('Access-Control-Max-Age', '3600');
    return res.status(204).send('');
  }

  const url = req.query.url || (req.body && req.body.url);

  if (!url) {
    return res.status(400).json({ error: 'URL parameter is required' });
  }

  fetchUrlMetadata(url, (error, metadata) => {
    if (error) {
      return res.status(500).json({ error: error.message });
    }
    res.status(200).json(metadata);
  });
};

